// WaveSpeed video generation — runs through the secure backend (/api/video)
async function generateVideo(prompt, image) {
  try {
    const res = await fetch("/api/video", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ prompt, image })
    });
    return await res.json();
  } catch { return { error: "Couldn't reach the video service." }; }
}

async function pollVideo(taskId) {
  for (let i = 0; i < 60; i++) {
    await new Promise(r => setTimeout(r, 3000));
    try {
      const res = await fetch("/api/video-result", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: taskId })
      });
      const data = await res.json();
      if (data.status === "completed") return data.output || null;
      if (data.status === "failed") return null;
    } catch {}
  }
  return null;
}

// ElevenLabs voiceover generation
async function generateVoiceover(text, voiceId="JBFqnCBsd6RMkjVDRZzb") {
  const res = await fetch("/api/voice", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ text, voiceId })
  });
  if (!res.ok) {
    let msg = "Voiceover failed";
    try { const d = await res.json(); msg = d.error || msg; } catch (_) {}
    throw new Error(msg);
  }
  const blob = await res.blob();
  return URL.createObjectURL(blob);
}

