          <Btn dark disabled={cLoad||!cBiz.trim()||!cTopic.trim()} onClick={genC}>{cLoad?"GENERATING...":cType==="seo"?"GENERATE SEO CONTENT":"GENERATE CONTENT"}</Btn>
